/**
 * MedX navbar layout runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Primary navigation item layout and badges.
 */
const NAVBAR_TOKENS = Object.freeze({
  primary: { value: "layout-navbar-primary", scope: "layout" },
  secondary: { value: "layout-navbar-secondary", scope: "layout" },
  muted: { value: "layout-navbar-muted", scope: "layout" },
  accent: { value: "layout-navbar-accent", scope: "layout" },
  surface: { value: "layout-navbar-surface", scope: "layout" },
});

const NAVBAR_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const NAVBAR_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const navbarRegistry = new Map();
const NAVBAR_listeners = new Set();
let NAVBAR_seq = 0;

function createNavbarId(prefix = "medx-layout-navbar") {
  NAVBAR_seq += 1;
  return `${prefix}-${NAVBAR_seq}`;
}

function registerNavbar(config = {}) {
  const entryId = config.id ?? createNavbarId();
  const preset = NAVBAR_PRESETS[config.preset ?? "default"] ?? NAVBAR_PRESETS.default;
  const token = NAVBAR_TOKENS[config.token ?? preset.token] ?? NAVBAR_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: NAVBAR_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  navbarRegistry.set(entryId, entry);
  notifyNavbarListeners("register", entry);
  return entry;
}

function updateNavbar(id, patch = {}) {
  const entry = navbarRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyNavbarListeners("update", entry);
  return entry;
}

function resolveNavbar(id) {
  const entry = navbarRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listNavbarEntries(filter = {}) {
  let items = Array.from(navbarRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onNavbarEvent(listener) {
  NAVBAR_listeners.add(listener);
  return () => NAVBAR_listeners.delete(listener);
}

function notifyNavbarListeners(type, entry) {
  for (const listener of NAVBAR_listeners) {
    try {
      listener({ type, entry, registrySize: navbarRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:layout:navbar] listener error", err.message);
    }
  }
}

function getNavbarMetrics() {
  const items = listNavbarEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(NAVBAR_TOKENS).length,
    presets: Object.keys(NAVBAR_PRESETS).length,
  };
}

async function runMedxNavbar() {
  console.log("[medx:ui:layout:navbar] runtime initialized");
  console.log(`[medx:ui:layout:navbar] tokens=${Object.keys(NAVBAR_TOKENS).length} presets=${Object.keys(NAVBAR_PRESETS).length}`);

  const events = [];
  onNavbarEvent((e) => events.push(e.type));

  const domains = Object.keys(NAVBAR_SUPPLY_CHAIN);
  const presets = Object.keys(NAVBAR_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerNavbar({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "layout/navbar" },
    });
  }

  const first = listNavbarEntries()[0];
  if (first) updateNavbar(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getNavbarMetrics();
  const resolved = first ? resolveNavbar(first.id) : null;

  console.log(`[medx:ui:layout:navbar] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:layout:navbar] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:layout:navbar] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:layout:navbar] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:layout:navbar] bootstrap complete");
}

module.exports = runMedxNavbar;
